'use client';
import Link from 'next/link';
import { useState } from 'react';

export default function Navbar({ user }: { user?: any }) {
  const [open, setOpen] = useState(false);
  return (
    <header className="sticky top-0 z-50 bg-white/80 backdrop-blur border-b">
      <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
        <Link href="/" className="font-extrabold text-xl">PlantCare</Link>
        <nav className="hidden md:flex gap-6 text-sm">
          <Link href="/">Home</Link>
          <Link href="/search">Search</Link>
          <Link href="/reminders">Your Reminders</Link>
          <Link href="/about">About Plants</Link>
        </nav>
        <div className="flex items-center gap-3">
          <Link href="/search" className="rounded-xl border px-3 py-1.5 text-sm">🔎 Search</Link>
          <div className="relative">
            <button onClick={()=>setOpen(!open)} className="size-9 rounded-full bg-gray-200 grid place-items-center">{user? '🧑' : '❔'}</button>
            {open && (
              <div className="absolute right-0 mt-2 w-56 rounded-xl border bg-white shadow">
                <div className="p-3 text-sm">
                  {user ? (
                    <>
                      <div className="font-semibold">{user.profile?.fullName || user.email}</div>
                      <div className="text-gray-500 text-xs">{user.email}</div>
                      <div className="h-px bg-gray-100 my-2" />
                      <Link href="/profile" className="block py-1">Profile</Link>
                      <Link href="/reminders" className="block py-1">Your Reminders</Link>
                      <a href="/api/auth/logout" className="block py-1">Sign out</a>
                    </>
                  ) : (
                    <>
                      <Link href="/login" className="block py-1">Sign in</Link>
                      <Link href="/signup" className="block py-1">Create account</Link>
                    </>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </header>
  );
}
